@SuppressWarnings({ "rawtypes", "unchecked" })
public <T> T mock(Class<T> clazz) {
    ClassLoader classloader = Thread.currentThread().getContextClassLoader();
    MockSettings settings = new MockSettings(configurableModeFor(clazz), noOpAdditionalInterfacesFor(clazz));
    if (!settings.isMockCreationEnabled()) {
        failBecauseOfConfiguration("Unable to create mock using Mockito for class: " + clazz);
    }

    // Create Proxy or spy based on settings.
    final Object result;
    if ((result = createMockOrNullProxyBasedOnSettingsAndConfigs(clazz, settings)) != null) {
        return (T) result;
    }
    checkNotClosed(session, sessionOpenMarker, "An attempt was made to reuse the Mockito Session.");

    // Checking for interface types is necessary as Mockito mocks implement all their interfaces, even those which do not exist in the actual class hierarchy.
    if (clazz.isInterface()) {
        MockitoSession activeMockitoSession = getActiveMockitoSession(session);
        if (activeMockitoSession.hasRegisteredMockFor(clazz)) {
            return (T) activeMockitoSession.registeredMocksByType().get(clazz);
        }

        MockTypeFactory factory = new MockTypeFactory(typeErasureResolver());
        Class<?> mockType = factory.createStubOrSpyFor(clazz);
        if (!clazz.equals(mockType)) {
            // If we found another class from which a proxy should be created - delegate to that one.
            return mock(mockType);
        }

        addRegisteredMockToCurrentSessionIfPossible(session, typeErasureResolver().resolveRawType(clazz), result);
        return (T) result;
    }
    assertMockCreationIsAllowedFor(clazz, settings);

